export const revalidate = 21600

async function resolveSearchParams(input?: Promise<SearchParams> | SearchParams) {
  if (!input) return {} as SearchParams
  if (typeof (input as Promise<SearchParams>).then === "function") {
    return (await input) || {}
  }
  return input
}

function getSingleParam(value?: string | string[]) {
  if (Array.isArray(value)) return String(value[0] || "")
  return String(value || "")
}

function buildBreedHref(query?: string, group?: string) {
  const params = new URLSearchParams()
  if (query) params.set("q", query)
  if (group) params.set("grupo", group)
  const search = params.toString()
  return search ? `/racas?${search}` : "/racas"
}

function buildPageTitle(query: string, selectedGroup: string) {
  if (query) {
    return `Resultados para \"${query}\"`
  }

  if (selectedGroup) {
    return `Grupo: ${translateBreedGroup(selectedGroup)}`
  }

  return "Explorador de racas"
}

function rankFeaturedProfiles(profiles: BreedStudyProfile[]) {
  const featuredOrder = new Map(FEATURED_BREED_NAMES.map((name, index) => [normalizeBreedSearchTerm(name), index]))

  return profiles.sort((left, right) => {
    const leftIndex = featuredOrder.get(normalizeBreedSearchTerm(left.breed.name))
    const rightIndex = featuredOrder.get(normalizeBreedSearchTerm(right.breed.name))

    if (typeof leftIndex === "number" && typeof rightIndex === "number") {
      return leftIndex - rightIndex
    }

    if (typeof leftIndex === "number") return -1
    if (typeof rightIndex === "number") return 1

    return left.breed.name.localeCompare(right.breed.name, "pt-BR")
  })
}

export async function generateMetadata({ searchParams }: Props): Promise<Metadata> {
  const resolved = await resolveSearchParams(searchParams)
  const query = getSingleParam(resolved.q).trim()
  const selectedGroup = getSingleParam(resolved.grupo).trim()
  const normalizedQuery = normalizeBreedSearchAlias(query)

  const title = query
    ? `${query} | Racas | K9 Training Platform`
    : selectedGroup
      ? `${translateBreedGroup(selectedGroup)} | Racas | K9 Training Platform`
      : "Racas | K9 Training Platform"

  const description = query
    ? `Explore racas relacionadas a ${query}, com busca adaptada para portugues, radar de encaixe e consultoria guiada.`
    : selectedGroup
      ? `Explore o grupo ${translateBreedGroup(selectedGroup)} com comparador, radar de encaixe e leitura guiada por IA.`
      : "Explore racas com busca em portugues, comparador, radar de encaixe e consultoria guiada para a vida real."

  return {
    title,
    description,
    alternates: {
      canonical: selectedGroup || query ? buildBreedHref(query || undefined, selectedGroup || undefined) : "/racas",
    },
    openGraph: {
      title,
      description,
      type: "website",
    },
    keywords: ["racas de caes", "pastor alemao", "golden retriever", normalizedQuery, selectedGroup].filter(Boolean),
  }
}

